  1→import React, { useState } from 'react';
  2→import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
  3→import { scanReputation, generateReputationResponse } from '../services/reputation_service';
  4→import { useTranslation } from '../i18n';
  5→import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→}
 12→
 13→const AI_LOGOS: Record<string, string> = {
 14→  ChatGPT: 'bg-purple-500/20 text-purple-300',
 15→  Perplexity: 'bg-blue-500/20 text-blue-400',
 16→  Claude: 'bg-orange-500/20 text-orange-400',
 17→  Gemini: 'bg-purple-500/20 text-purple-400',
 18→  Copilot: 'bg-cyan-500/20 text-cyan-400',
 19→};
 20→
 21→const SEVERITY_CONFIG = {
 22→  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
 23→  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-purple-500/20' },
 24→  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
 25→};
 26→
 27→const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
 28→  const { t, locale } = useTranslation();
 29→
 30→  const SENTIMENT_CONFIG = {
 31→    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-purple-500/20', label: t.reputation.positive },
 32→    neutral: { color: 'text-gray-400', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: t.reputation.neutral },
 33→    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: t.reputation.negative },
 34→  };
 35→
 36→  const [step, setStep] = useState<'form' | 'results'>('form');
 37→  const [isScanning, setIsScanning] = useState(false);
 38→  const [report, setReport] = useState<ReputationReport | null>(null);
 39→
 40→  // Form
 41→  const [brandName, setBrandName] = useState('');
 42→  const [brandUrl, setBrandUrl] = useState('');
 43→  const [industry, setIndustry] = useState('');
 44→  const [competitorInput, setCompetitorInput] = useState('');
 45→  const [competitors, setCompetitors] = useState<string[]>([]);
 46→  const [keywordInput, setKeywordInput] = useState('');
 47→  const [keywords, setKeywords] = useState<string[]>([]);
 48→
 49→  // Action plan
 50→  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
 51→  const [actionPlan, setActionPlan] = useState<string | null>(null);
 52→  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
 53→  const [copied, setCopied] = useState(false);
 54→
 55→  const addCompetitor = () => {
 56→    if (competitorInput.trim() && competitors.length < 5) {
 57→      setCompetitors([...competitors, competitorInput.trim()]);
 58→      setCompetitorInput('');
 59→    }
 60→  };
 61→
 62→  const addKeyword = () => {
 63→    if (keywordInput.trim() && keywords.length < 10) {
 64→      setKeywords([...keywords, keywordInput.trim()]);
 65→      setKeywordInput('');
 66→    }
 67→  };
 68→
 69→  const handleScan = async () => {
 70→    if (!brandName || !industry) {
 71→      alert(locale === 'en' ? 'Please fill in the brand name and industry.' : locale === 'es' ? 'Por favor, rellena el nombre de la marca y el sector.' : 'Veuillez remplir le nom de la marque et le secteur.');
 72→      return;
 73→    }
 74→
 75→    const canProceed = onDeductCredits(3);
 76→    if (!canProceed) return;
 77→
 78→    setIsScanning(true);
 79→    try {
 80→      const result = await scanReputation({
 81→        brandName,
 82→        brandUrl: brandUrl || undefined,
 83→        competitors: competitors.length > 0 ? competitors : undefined,
 84→        industry,
 85→        keywords: keywords.length > 0 ? keywords : undefined,
 86→      }, locale as 'fr' | 'en' | 'es');
 87→      setReport(result);
 88→      setStep('results');
 89→    } catch (error) {
 90→      console.error(error);
 91→      alert(locale === 'en' ? 'Scan error.' : locale === 'es' ? 'Error de escaneo.' : 'Erreur lors du scan.');
 92→    } finally {
 93→      setIsScanning(false);
 94→    }
 95→  };
 96→
 97→  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
 98→    setExpandedAlert(index);
 99→    setIsGeneratingPlan(true);
100→    setActionPlan(null);
101→    try {
102→      const plan = await generateReputationResponse(alert, brandName, locale as 'fr' | 'en' | 'es');
103→      setActionPlan(plan);
104→    } catch (e) {
105→      setActionPlan(locale === 'en' ? 'Error generating action plan.' : locale === 'es' ? 'Error al generar el plan de accion.' : "Erreur lors de la generation du plan d'action.");
106→    } finally {
107→      setIsGeneratingPlan(false);
108→    }
109→  };
110→
111→  const handleCopy = (text: string) => {
112→    navigator.clipboard.writeText(text);
113→    setCopied(true);
114→    setTimeout(() => setCopied(false), 2000);
115→  };
116→
117→  // Sentiment Gauge
118→  const SentimentGauge = ({ value }: { value: number }) => {
119→    const normalized = (value + 100) / 200;
120→    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
121→    return (
122→      <div className="w-full">
123→        <div className="flex justify-between text-xs text-gray-500 mb-1">
124→          <span>-100</span><span>0</span><span>+100</span>
125→        </div>
126→        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
127→          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
128→        </div>
129→        <div className="text-center mt-2">
130→          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
131→          <span className="text-xs text-gray-500 ml-1">sentiment</span>
132→        </div>
133→      </div>
134→    );
135→  };
136→
137→  // Score Ring
138→  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
139→    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
140→    const circumference = 2 * Math.PI * 36;
141→    const offset = circumference - (score / 100) * circumference;
142→    return (
143→      <div className="flex flex-col items-center">
144→        <div className="relative w-24 h-24">
145→          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
146→            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
147→            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
148→          </svg>
149→          <div className="absolute inset-0 flex items-center justify-center">
150→            <span className="text-2xl font-bold text-white">{score}</span>
151→          </div>
152→        </div>
153→        <span className="text-xs text-gray-400 mt-2">{label}</span>
154→      </div>
155→    );
156→  };
157→
158→  return (
159→    <div className="max-w-6xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-screen">
160→      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
161→        <ArrowLeft size={18} className="mr-2" /> {t.common.back}
162→      </button>
163→
164→      {/* Header */}
165→      <div className="flex items-center gap-4 mb-10">
166→        <div className="p-3 bg-purple-500/10 rounded-2xl">
167→          <Shield size={32} className="text-purple-400" />
168→        </div>
169→        <div>
170→          <h1 className="text-3xl font-bold text-white">{t.reputation.title}</h1>
171→          <p className="text-gray-400">{t.reputation.subtitle}</p>
172→        </div>
173→        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-purple-500/20">
174→          {t.reputation.heuristicBadge}
175→        </span>
176→      </div>
177→
178→      {/* Form */}
179→      {step === 'form' && (
180→        <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6 space-y-5">
181→          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
182→            <div>
183→              <label className="block text-sm text-gray-400 mb-1.5">{t.reputation.brandName} *</label>
184→              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
185→            </div>
186→            <div>
187→              <label className="block text-sm text-gray-400 mb-1.5">{t.reputation.brandUrl} ({t.common.optional})</label>
188→              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
189→            </div>
190→          </div>
191→          <div>
192→            <label className="block text-sm text-gray-400 mb-1.5">{t.reputation.industry} *</label>
193→            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
194→          </div>
195→
196→          {/* Competitors */}
197→          <div>
198→            <label className="block text-sm text-gray-400 mb-1.5">{t.reputation.competitors}</label>
199→            <div className="flex gap-2">
200→              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
201→              <button onClick={addCompetitor} className="px-4 bg-purple-500/5 border border-white/10 rounded-lg hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-400" /></button>
202→            </div>
203→            {competitors.length > 0 && (
204→              <div className="flex flex-wrap gap-2 mt-2">
205→                {competitors.map((c, i) => (
206→                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-purple-500/20">
207→                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
208→                  </span>
209→                ))}
210→              </div>
211→            )}
212→          </div>
213→
214→          {/* Keywords */}
215→          <div>
216→            <label className="block text-sm text-gray-400 mb-1.5">{t.reputation.keywords}</label>
217→            <div className="flex gap-2">
218→              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
219→              <button onClick={addKeyword} className="px-4 bg-purple-500/5 border border-white/10 rounded-lg hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-400" /></button>
220→            </div>
221→            {keywords.length > 0 && (
222→              <div className="flex flex-wrap gap-2 mt-2">
223→                {keywords.map((k, i) => (
224→                  <span key={i} className="flex items-center gap-1 bg-purple-500/5 text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/10">
225→                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
226→                  </span>
227→                ))}
228→              </div>
229→            )}
230→          </div>
231→
232→          <div className="bg-purple-500/5 border border-purple-500/10 rounded-lg p-4 text-sm text-gray-400">
233→            <div className="flex items-start gap-2">
234→              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
235→              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
236→            </div>
237→          </div>
238→
239→          <button
240→            onClick={handleScan}
241→            disabled={isScanning || !brandName || !industry}
242→            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
243→          >
244→            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
245→          </button>
246→        </div>
247→      )}
248→
249→      {/* Results */}
250→      {step === 'results' && report && (
251→        <div className="space-y-6">
252→          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>
253→
254→          {/* Dashboard Cards */}
255→          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
256→            <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6 flex flex-col items-center">
257→              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
258→            </div>
259→            <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
260→              <SentimentGauge value={report.overallSentiment} />
261→            </div>
262→            <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
263→              <h4 className="text-sm font-bold text-gray-400 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
264→              <div className="space-y-3">
265→                {(['positive', 'neutral', 'negative'] as const).map(s => {
266→                  const count = report.sentimentBreakdown[s];
267→                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
268→                  const cfg = SENTIMENT_CONFIG[s];
269→                  return (
270→                    <div key={s}>
271→                      <div className="flex justify-between text-xs mb-1">
272→                        <span className={cfg.color}>{cfg.label}</span>
273→                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
274→                      </div>
275→                      <div className="h-2 bg-purple-500/5 rounded-full overflow-hidden">
276→                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
277→                      </div>
278→                    </div>
279→                  );
280→                })}
281→              </div>
282→            </div>
283→          </div>
284→
285→          {/* Top Themes */}
286→          <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
287→            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
288→            <div className="flex flex-wrap gap-2">
289→              {report.topThemes.map((theme, i) => {
290→                const cfg = SENTIMENT_CONFIG[theme.sentiment];
291→                return (
292→                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
293→                    {theme.theme} ({theme.count})
294→                  </span>
295→                );
296→              })}
297→            </div>
298→          </div>
299→
300→          {/* Competitor Comparison */}
301→          {report.competitorComparison && report.competitorComparison.length > 0 && (
302→            <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
303→              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
304→              <div className="overflow-x-auto">
305→                <table className="w-full text-sm">
306→                  <thead>
307→                    <tr className="border-b border-white/5">
308→                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
309→                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
310→                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
311→                    </tr>
312→                  </thead>
313→                  <tbody>
314→                    <tr className="border-b border-white/5 bg-purple-500/5">
315→                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
316→                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
317→                      <td className="py-3 text-center">
318→                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-400'}>
319→                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
320→                        </span>
321→                      </td>
322→                    </tr>
323→                    {report.competitorComparison.map((c, i) => (
324→                      <tr key={i} className="border-b border-white/5">
325→                        <td className="py-3 text-gray-300">{c.name}</td>
326→                        <td className="py-3 text-center text-white">{c.mentions}</td>
327→                        <td className="py-3 text-center">
328→                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-400'}>
329→                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
330→                          </span>
331→                        </td>
332→                      </tr>
333→                    ))}
334→                  </tbody>
335→                </table>
336→              </div>
337→            </div>
338→          )}
339→
340→          {/* Alerts */}
341→          <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
342→            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
343→            <div className="space-y-3">
344→              {report.alerts.map((alert, i) => {
345→                const cfg = SEVERITY_CONFIG[alert.severity];
346→                const SevIcon = cfg.icon;
347→                const isExpanded = expandedAlert === i;
348→                return (
349→                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-xl p-4`}>
350→                    <div className="flex items-start gap-3">
351→                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
352→                      <div className="flex-1">
353→                        <p className="text-sm text-gray-200">{alert.message}</p>
354→                        <p className="text-xs text-gray-400 mt-1">Action : {alert.action}</p>
355→                      </div>
356→                      <button
357→                        onClick={() => handleGenerateActionPlan(alert, i)}
358→                        className={`text-xs px-3 py-1.5 rounded-lg border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
359→                      >
360→                        <Sparkles size={12} /> {t.reputation.actionPlan}
361→                      </button>
362→                    </div>
363→                    {isExpanded && (
364→                      <div className="mt-4 pt-4 border-t border-white/5">
365→                        {isGeneratingPlan ? (
366→                          <div className="flex items-center gap-2 text-sm text-gray-400"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
367→                        ) : actionPlan ? (
368→                          <div>
369→                            <div className="flex justify-end mb-2">
370→                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
371→                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
372→                              </button>
373→                            </div>
374→                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
375→                          </div>
376→                        ) : null}
377→                      </div>
378→                    )}
379→                  </div>
380→                );
381→              })}
382→            </div>
383→          </div>
384→
385→          {/* Mentions */}
386→          <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
387→            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
388→            <div className="space-y-3">
389→              {report.mentions.map((mention) => {
390→                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
391→                return (
392→                  <div key={mention.id} className="bg-black/20 border border-white/5 rounded-xl p-4">
393→                    <div className="flex items-center gap-3 mb-3">
394→                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-400'}`}>
395→                        {mention.aiEngine}
396→                      </span>
397→                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
398→                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
399→                      </span>
400→                      <span className="text-xs text-gray-600 bg-purple-500/5 px-2 py-0.5 rounded">{mention.mentionType}</span>
401→                    </div>
402→                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
403→                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
404→                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
405→                  </div>
406→                );
407→              })}
408→            </div>
409→          </div>
410→
411→          {/* Recommendations */}
412→          <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
413→            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
414→            <div className="space-y-2">
415→              {report.recommendations.map((rec, i) => (
416→                <div key={i} className="flex items-start gap-3 py-2">
